def parse_client(nombres, apellido_paterno, apellido_materno, contacto, direccion, edad=None):
    raw = {
        "nombres_raw": nombres,
        "apellido_paterno_raw": apellido_paterno,
        "apellido_materno_raw": apellido_materno,
        "contacto_raw": contacto,
        "direccion_raw": direccion,
        "edad_raw": edad,
    }
    errors = []
    clean = {}
    for key, val in [
        ("nombres", nombres),
        ("apellido_paterno", apellido_paterno),
        ("apellido_materno", apellido_materno),
        ("contacto", contacto),
        ("direccion", direccion),
    ]:
        t = (val or "").strip()
        if t == "":
            clean[key] = None
            errors.append(f"ERROR en '{key}': vacío (raw={val!r})")
        else:
            clean[key] = t
    if edad is None:
        clean["edad"] = None
    else:
        ok, n, msg = safe_int("edad", str(edad))
        clean["edad"] = n
        if not ok:
            errors.append(msg)
    return {**raw, **clean, "errors": errors}

